<style>
    :root {
      --bg: #f6f7fb;
      --card: #ffffff;
      --text: #1f2937;
      --muted: #6b7280;
      --primary: #2563eb;
      --primary-soft: #dbeafe;
      --border: #d1d5db;
      --danger: #ef4444;
      --success: #16a34a;
      --warning: #f59e0b;
    }

    body {
      margin: 0;
