    opciones: [
      "HCl / NaOH",
      "NH₄⁺ / NH₃",
      "NaCl / H₂O",
      "H₂SO₄ / Ca(OH)₂"
    ],
    correcta: 1,
    explicacion: "NH₄⁺ y NH₃ solo se diferencian en un protón H⁺. Por eso forman un par ácido-base conjugado."
  }
];

let contestadasFundamentosAB = new Array(preguntasFundamentosAB.length).fill(false);
let puntuacionFundamentosAB = 0;

function cargarFundamentosAB() {
  const contenedor = document.getElementById("preguntas-fundamentos-ab");
  contenedor.innerHTML = "";

  preguntasFundamentosAB.forEach((pregunta, i) => {
    const bloque = document.createElement("div");
    bloque.style.background = "white";
    bloque.style.border = "1px solid #cbd5e1";
    bloque.style.borderRadius = "16px";
    bloque.style.padding = "16px";
    bloque.style.marginTop = "16px";
    bloque.style.boxShadow = "0 4px 12px rgba(15,23,42,0.06)";

    const titulo = document.createElement("p");
    titulo.innerHTML = "<strong>" + pregunta.enunciado + "</strong>";
    bloque.appendChild(titulo);

    pregunta.opciones.forEach((opcion, j) => {
      const boton = document.createElement("button");
      boton.innerHTML = opcion;
      boton.style.display = "block";
      boton.style.width = "100%";
      boton.style.textAlign = "left";
      boton.style.margin = "8px 0";
      boton.style.padding = "10px";
      boton.style.borderRadius = "10px";
      boton.style.border = "1px solid #cbd5e1";
      boton.style.background = "#f8fafc";
      boton.style.cursor = "pointer";

      boton.onclick = function() {
        corregirFundamentosAB(i, j, boton);
      };

      bloque.appendChild(boton);
    });

    const feedback = document.createElement("p");
    feedback.id = "feedback-fundamentos-ab-" + i;
    feedback.style.fontWeight = "bold";
    feedback.style.marginTop = "10px";
    bloque.appendChild(feedback);

    contenedor.appendChild(bloque);
  });

  actualizarResultadoFundamentosAB();
}

function corregirFundamentosAB(i, j, botonPulsado) {
  const pregunta = preguntasFundamentosAB[i];
  const feedback = document.getElementById("feedback-fundamentos-ab-" + i);
  const botones = botonPulsado.parentElement.querySelectorAll("button");

  if (!contestadasFundamentosAB[i]) {
    contestadasFundamentosAB[i] = true;
    if (j === pregunta.correcta) {
      puntuacionFundamentosAB++;
    }
  }

  botones.forEach((boton, indice) => {
    boton.disabled = true;
    boton.style.cursor = "default";

    if (indice === pregunta.correcta) {
      boton.style.background = "#dcfce7";
      boton.style.border = "1px solid #22c55e";
    } else if (indice === j) {
      boton.style.background = "#fee2e2";
      boton.style.border = "1px solid #ef4444";
    }
  });

  if (j === pregunta.correcta) {
    feedback.style.color = "#166534";
    feedback.innerHTML = "Correcto. " + pregunta.explicacion;
  } else {
    feedback.style.color = "#991b1b";
    feedback.innerHTML = "No es correcto. " + pregunta.explicacion;
  }

  actualizarResultadoFundamentosAB();
}

function actualizarResultadoFundamentosAB() {
  const respondidas = contestadasFundamentosAB.filter(x => x).length;
  const resultado = document.getElementById("resultado-fundamentos-ab");
  resultado.innerHTML = "Puntuación: " + puntuacionFundamentosAB + "/" + preguntasFundamentosAB.length +
  " | Preguntas respondidas: " + respondidas + "/" + preguntasFundamentosAB.length;
}

function reiniciarFundamentosAB() {
  contestadasFundamentosAB = new Array(preguntasFundamentosAB.length).fill(false);
  puntuacionFundamentosAB = 0;
  cargarFundamentosAB();
}

cargarFundamentosAB();
</script>
