{"ideviceId":"202604271840472013B2","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<div id="calculadora-ph-poh" style="font-family: Arial, sans-serif; line-height: 1.6; background: #f8fafc; border: 1px solid #dbeafe; border-radius: 18px; padding: 22px;">
<h2 style="color: #1d4ed8; margin-top: 0;">Mini calculadora de pH y pOH</h2>
<p>Introduce una concentración de H<sub>3</sub>O<sup>+</sup> o de OH<sup>-</sup> y la calculadora te dirá el pH, el pOH y el carácter de la disolución.</p>
<div style="background: white; border: 1px solid #cbd5e1; border-radius: 16px; padding: 16px; margin-top: 16px;"><label for="tipo-concentracion-ph" style="font-weight: bold;">¿Qué concentración quieres introducir?</label><select id="tipo-concentracion-ph" style="display: block; width: 100%; padding: 10px; border-radius: 10px; border: 1px solid #cbd5e1; margin: 8px 0 14px;">
<option value="h">[H₃O⁺]</option>
<option value="oh">[OH⁻]</option>
</select><label for="valor-concentracion-ph" style="font-weight: bold;">Concentración en mol/L</label> <input id="valor-concentracion-ph" type="number" step="any" value="0.001" style="display: block; width: 100%; padding: 10px; border-radius: 10px; border: 1px solid #cbd5e1; margin: 8px 0 14px;" /> <button onclick="calcularPHPoh()" style="background: #2563eb; color: white; border: none; padding: 12px 18px; border-radius: 12px; font-weight: bold; cursor: pointer;"> Calcular </button>
<div id="resultado-ph-poh" style="margin-top: 18px; background: #ffffff; border-radius: 14px; padding: 14px; border: 1px solid #cbd5e1;"></div>
<div style="height: 22px; background: linear-gradient(90deg,#ef4444,#facc15,#22c55e,#38bdf8,#2563eb); border-radius: 12px; margin-top: 16px; position: relative;">
<div id="marcador-ph" style="position: absolute; top: -6px; width: 4px; height: 34px; background: #111827; left: 50%; border-radius: 4px;"></div>
</div>
<div style="display: flex; justify-content: space-between; font-size: 13px; margin-top: 4px;"><span>pH 0</span> <span>pH 7</span> <span>pH 14</span></div>
</div>
</div>
<p>
<script>
function calcularPHPoh() {
  const tipo = document.getElementById("tipo-concentracion-ph").value;
  const valor = parseFloat(document.getElementById("valor-concentracion-ph").value);
  const resultado = document.getElementById("resultado-ph-poh");
  const marcador = document.getElementById("marcador-ph");

  if (isNaN(valor) || valor <= 0) {
    resultado.innerHTML = "<p style='color:#991b1b; font-weight:bold;'>Introduce una concentración positiva.</p>";
    return;
  }

  let pH, pOH;

  if (tipo === "h") {
    pH = -Math.log10(valor);
    pOH = 14 - pH;
  } else {
    pOH = -Math.log10(valor);
    pH = 14 - pOH;
  }

  let caracter = "";
  let color = "";

  if (pH < 7) {
    caracter = "ácida";
    color = "#991b1b";
  } else if (pH > 7) {
    caracter = "básica";
    color = "#1d4ed8";
  } else {
    caracter = "neutra";
    color = "#166534";
  }

  const posicion = Math.max(0, Math.min(100, (pH / 14) * 100));
  marcador.style.left = posicion + "%";

  resultado.innerHTML =
    "<p><strong>pH:</strong> " + pH.toFixed(2) + "</p>" +
    "<p><strong>pOH:</strong> " + pOH.toFixed(2) + "</p>" +
    "<p style='color:" + color + "; font-weight:bold;'>La disolución es " + caracter + ".</p>" +
    "<p style='font-size:14px;'>Recuerda: estos cálculos se hacen suponiendo 25 ºC, donde pH + pOH = 14.</p>";
}

calcularPHPoh();
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

{"ideviceId":"202604271841194811K5","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<div id="autocorregible-ph-poh" style="font-family: Arial, sans-serif; line-height: 1.6; background: #f8fafc; border: 1px solid #dbeafe; border-radius: 18px; padding: 22px;">
<h2 style="color: #1d4ed8; margin-top: 0;">Autocorregible: pH, pOH y mezclas</h2>
<p>Responde a estas preguntas para comprobar si dominas Kw, pH, pOH, ácidos fuertes, bases fuertes y mezclas sencillas.</p>
<div id="preguntas-ph-poh"></div>
<button onclick="reiniciarPHPoh()" style="margin-top: 18px; background: #2563eb; color: white; border: none; padding: 12px 18px; border-radius: 12px; font-weight: bold; cursor: pointer;"> Reiniciar actividad </button>
<p id="resultado-ph-poh-quiz" style="font-weight: bold; font-size: 18px; margin-top: 16px;"></p>
</div>
<p>
<script>
const preguntasPHPoh = [
  {
    enunciado: "1. A 25 ºC, el producto iónico del agua vale:",
    opciones: [
      "1,0·10⁻⁷",
      "1,0·10⁻¹⁴",
      "14",
      "7"
    ],
    correcta: 1,
    explicacion: "A 25 ºC, Kw = [H₃O⁺][OH⁻] = 1,0·10⁻¹⁴."
  },
  {
    enunciado: "2. Si [H₃O⁺] = 1,0·10⁻³ M, el pH vale:",
    opciones: [
      "3",
      "11",
      "7",
      "10⁻³"
    ],
    correcta: 0,
    explicacion: "pH = -log(1,0·10⁻³) = 3."
  },
  {
    enunciado: "3. Si pOH = 5, el pH vale:",
    opciones: [
      "5",
      "7",
      "9",
      "14"
    ],
    correcta: 2,
    explicacion: "A 25 ºC, pH + pOH = 14. Por tanto, pH = 14 - 5 = 9."
  },
  {
    enunciado: "4. Una disolución con pH = 2 es:",
    opciones: [
      "Ácida",
      "Básica",
      "Neutra",
      "Siempre tampón"
    ],
    correcta: 0,
    explicacion: "Si pH < 7, la disolución es ácida."
  },
  {
    enunciado: "5. Una disolución con pH = 12 es:",
    opciones: [
      "Ácida",
      "Básica",
      "Neutra",
      "Siempre ácida"
    ],
    correcta: 1,
    explicacion: "Si pH > 7, la disolución es básica."
  },
  {
    enunciado: "6. ¿Cuál es el pH de HCl 0,01 M?",
    opciones: [
      "1",
      "2",
      "7",
      "12"
    ],
    correcta: 1,
    explicacion: "HCl es ácido fuerte y aporta 1 H⁺ por mol. [H₃O⁺] = 0,01 M = 10⁻² M. Por tanto, pH = 2."
  },
  {
    enunciado: "7. ¿Cuál es el pH de NaOH 0,001 M?",
    opciones: [
      "3",
      "7",
      "11",
      "13"
    ],
    correcta: 2,
    explicacion: "NaOH aporta [OH⁻] = 10⁻³ M. pOH = 3 y pH = 14 - 3 = 11."
  },
  {
    enunciado: "8. En PAU, si tratamos H₂SO₄ 0,01 M como ácido fuerte que aporta 2 H⁺, [H₃O⁺] será:",
    opciones: [
      "0,005 M",
      "0,01 M",
      "0,02 M",
      "2 M"
    ],
    correcta: 2,
    explicacion: "Cada mol de H₂SO₄ aporta 2 moles de H⁺. Por tanto, [H₃O⁺] = 2 · 0,01 = 0,02 M."
  },
  {
    enunciado: "9. Ca(OH)₂ 0,01 M aporta una concentración de OH⁻ igual a:",
    opciones: [
      "0,005 M",
      "0,01 M",
      "0,02 M",
      "1 M"
    ],
    correcta: 2,
    explicacion: "Cada mol de Ca(OH)₂ aporta 2 moles de OH⁻. Por tanto, [OH⁻] = 2 · 0,01 = 0,02 M."
  },
  {
    enunciado: "10. Se mezclan moles iguales de H⁺ y OH⁻ procedentes de ácido fuerte y base fuerte. El resultado será:",
    opciones: [
      "Exceso de ácido",
      "Exceso de base",
      "Neutralización completa",
      "Siempre tampón"
    ],
    correcta: 2,
    explicacion: "Si los moles de H⁺ y OH⁻ son iguales, la neutralización es completa."
  }
];

let contestadasPHPoh = new Array(preguntasPHPoh.length).fill(false);
let puntuacionPHPoh = 0;

function cargarPHPoh() {
  const contenedor = document.getElementById("preguntas-ph-poh");
  contenedor.innerHTML = "";

  preguntasPHPoh.forEach((pregunta, i) => {
    const bloque = document.createElement("div");
    bloque.style.background = "white";
    bloque.style.border = "1px solid #cbd5e1";
    bloque.style.borderRadius = "16px";
    bloque.style.padding = "16px";
    bloque.style.marginTop = "16px";
    bloque.style.boxShadow = "0 4px 12px rgba(15,23,42,0.06)";

    const titulo = document.createElement("p");
    titulo.innerHTML = "<strong>" + pregunta.enunciado + "</strong>";
    bloque.appendChild(titulo);

    pregunta.opciones.forEach((opcion, j) => {
      const boton = document.createElement("button");
      boton.innerHTML = opcion;
      boton.style.display = "block";
      boton.style.width = "100%";
      boton.style.textAlign = "left";
      boton.style.margin = "8px 0";
      boton.style.padding = "10px";
      boton.style.borderRadius = "10px";
      boton.style.border = "1px solid #cbd5e1";
      boton.style.background = "#f8fafc";
      boton.style.cursor = "pointer";

      boton.onclick = function() {
        corregirPHPoh(i, j, boton);
      };

      bloque.appendChild(boton);
    });

    const feedback = document.createElement("p");
    feedback.id = "feedback-ph-poh-" + i;
    feedback.style.fontWeight = "bold";
    feedback.style.marginTop = "10px";
    bloque.appendChild(feedback);

    contenedor.appendChild(bloque);
  });

  actualizarResultadoPHPoh();
}

function corregirPHPoh(i, j, botonPulsado) {
  const pregunta = preguntasPHPoh[i];
  const feedback = document.getElementById("feedback-ph-poh-" + i);
  const botones = botonPulsado.parentElement.querySelectorAll("button");

  if (!contestadasPHPoh[i]) {
    contestadasPHPoh[i] = true;
    if (j === pregunta.correcta) {
      puntuacionPHPoh++;
    }
  }

  botones.forEach((boton, indice) => {
    boton.disabled = true;
    boton.style.cursor = "default";

    if (indice === pregunta.correcta) {
      boton.style.background = "#dcfce7";
      boton.style.border = "1px solid #22c55e";
    } else if (indice === j) {
      boton.style.background = "#fee2e2";
      boton.style.border = "1px solid #ef4444";
    }
  });

  if (j === pregunta.correcta) {
    feedback.style.color = "#166534";
    feedback.innerHTML = "Correcto. " + pregunta.explicacion;
  } else {
    feedback.style.color = "#991b1b";
    feedback.innerHTML = "No es correcto. " + pregunta.explicacion;
  }

  actualizarResultadoPHPoh();
}

function actualizarResultadoPHPoh() {
  const respondidas = contestadasPHPoh.filter(x => x).length;
  const resultado = document.getElementById("resultado-ph-poh-quiz");
  resultado.innerHTML = "Puntuación: " + puntuacionPHPoh + "/" + preguntasPHPoh.length +
  " | Preguntas respondidas: " + respondidas + "/" + preguntasPHPoh.length;
}

function reiniciarPHPoh() {
  contestadasPHPoh = new Array(preguntasPHPoh.length).fill(false);
  puntuacionPHPoh = 0;
  cargarPHPoh();
}

cargarPHPoh();
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

{"ideviceId":"20260427184816074SY4","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<div id="calculadora-debiles-ab" style="font-family: Arial, sans-serif; line-height: 1.6; background: #f8fafc; border: 1px solid #dbeafe; border-radius: 18px; padding: 22px;">
<h2 style="color: #1d4ed8; margin-top: 0;">Mini calculadora: ácidos y bases débiles</h2>
<p>Introduce la concentración y la constante de equilibrio. La herramienta calcula una aproximación del pH y del grado de ionización.</p>
<div style="background: #fef3c7; border-left: 6px solid #f59e0b; padding: 14px; border-radius: 12px; margin: 16px 0;">
<p><strong>Importante:</strong> esta calculadora usa la aproximación habitual de PAU: C - x ≈ C. Es adecuada cuando la ionización es pequeña.</p>
</div>
<div style="background: white; border: 1px solid #cbd5e1; border-radius: 16px; padding: 16px; margin-top: 16px;"><label for="tipo-debil-ab" style="font-weight: bold;">Tipo de sustancia</label><select id="tipo-debil-ab" style="display: block; width: 100%; padding: 10px; border-radius: 10px; border: 1px solid #cbd5e1; margin: 8px 0 14px;">
<option value="acido">Ácido débil</option>
<option value="base">Base débil</option>
</select><label for="concentracion-debil-ab" style="font-weight: bold;">Concentración inicial C (mol/L)</label> <input id="concentracion-debil-ab" type="number" step="any" value="0.10" style="display: block; width: 100%; padding: 10px; border-radius: 10px; border: 1px solid #cbd5e1; margin: 8px 0 14px;" /> <label for="constante-debil-ab" style="font-weight: bold;">Ka o Kb</label> <input id="constante-debil-ab" type="number" step="any" value="0.000018" style="display: block; width: 100%; padding: 10px; border-radius: 10px; border: 1px solid #cbd5e1; margin: 8px 0 14px;" /> <button onclick="calcularDebilAB()" style="background: #2563eb; color: white; border: none; padding: 12px 18px; border-radius: 12px; font-weight: bold; cursor: pointer;"> Calcular </button>
<div id="resultado-debil-ab" style="margin-top: 18px; background: #ffffff; border-radius: 14px; padding: 14px; border: 1px solid #cbd5e1;"></div>
</div>
</div>
<p>
<script>
function calcularDebilAB() {
  const tipo = document.getElementById("tipo-debil-ab").value;
  const C = parseFloat(document.getElementById("concentracion-debil-ab").value);
  const K = parseFloat(document.getElementById("constante-debil-ab").value);
  const resultado = document.getElementById("resultado-debil-ab");

  if (isNaN(C) || isNaN(K) || C <= 0 || K <= 0) {
    resultado.innerHTML = "<p style='color:#991b1b; font-weight:bold;'>Introduce valores positivos para la concentración y la constante.</p>";
    return;
  }

  const x = Math.sqrt(K * C);
  const alpha = x / C;
  const porcentaje = alpha * 100;

  let pH, pOH, texto;

  if (tipo === "acido") {
    pH = -Math.log10(x);
    texto = "<p><strong>[H₃O⁺] ≈</strong> " + x.toExponential(3) + " M</p>" +
            "<p><strong>pH ≈</strong> " + pH.toFixed(2) + "</p>" +
            "<p><strong>Grado de ionización:</strong> " + alpha.toFixed(4) + " (" + porcentaje.toFixed(2) + " %)</p>" +
            "<p style='color:#991b1b; font-weight:bold;'>La disolución es ácida.</p>";
  } else {
    pOH = -Math.log10(x);
    pH = 14 - pOH;
    texto = "<p><strong>[OH⁻] ≈</strong> " + x.toExponential(3) + " M</p>" +
            "<p><strong>pOH ≈</strong> " + pOH.toFixed(2) + "</p>" +
            "<p><strong>pH ≈</strong> " + pH.toFixed(2) + "</p>" +
            "<p><strong>Grado de ionización:</strong> " + alpha.toFixed(4) + " (" + porcentaje.toFixed(2) + " %)</p>" +
            "<p style='color:#1d4ed8; font-weight:bold;'>La disolución es básica.</p>";
  }

  if (porcentaje > 5) {
    texto += "<p style='color:#92400e;'><strong>Aviso:</strong> el porcentaje de ionización supera el 5 %. La aproximación C - x ≈ C puede ser menos precisa.</p>";
  }

  resultado.innerHTML = texto;
}

calcularDebilAB();
</script>
</p>","textFeedbackInput":"Mostrar retroalimentación","textFeedbackTextarea":""}

{"ideviceId":"20260427184848895TE2","textInfoDurationInput":"","textInfoDurationTextInput":"Duración","textInfoParticipantsInput":"","textInfoParticipantsTextInput":"Agrupamiento","textTextarea":"<div id="autocorregible-debiles-ab" style="font-family: Arial, sans-serif; line-height: 1.6; background: #f8fafc; border: 1px solid #dbeafe; border-radius: 18px; padding: 22px;">
